class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def append(self, data):
        new_node = Node(data)
        if not self.head:
            self.head = new_node
            return
        last = self.head
        while last.next:
            last = last.next
        last.next = new_node

def find_triplet_sum_in_linked_list(head, target_sum):
    if not head or not head.next or not head.next.next:
        return None

    ptr1 = head
    while ptr1 is not None:
        target_two_sum = target_sum - ptr1.data

        ptr2 = ptr1.next
        seen_elements = set()

        while ptr2 is not None:
            complement = target_two_sum - ptr2.data

            if complement in seen_elements:
                return (ptr1.data, ptr2.data, complement)

            seen_elements.add(ptr2.data)
            ptr2 = ptr2.next

        ptr1 = ptr1.next

    return None
